                    'adroll.ended': () => {
                        window.isPlayingAdroll = false;
                        if(document.querySelector('.clipsEditor__clipsButtonBlock')) {
                            document.querySelector('.clipsEditor__clipsButtonBlock').classList.remove('displayNone');
                        }
